local xml_parser = require("LuaXML.parser")

-- Helper function to find a child node by tag name
local function find_child(node, tag_name)
    if not node or not node.children then
        return nil
    end
    for _, child in ipairs(node.children) do
        if type(child) == 'table' and child.tag == tag_name then
            return child
        end
    end
    return nil
end

-- Helper function to get the concatenated text content of a node
local function get_text_content(node)
    if not node or not node.children then
        return nil
    end
    local text_parts = {}
    for _, child in ipairs(node.children) do
        if type(child) == 'string' then
            table.insert(text_parts, child)
        end
    end
    return table.concat(text_parts)
end

-- Get the raw XML request body
local xml_request_body = ngx.req.get_body_data()

if not xml_request_body then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: No XML request body found.")
    return
end

local parser = xml_parser.new()
local parsed_xml, err = parser:parse(xml_request_body)

if not parsed_xml then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error parsing XML: ", err)
    ngx.log(ngx.ERR, "XML parsing error: ", err, " Body: ", xml_request_body)
    return
end

-- Example of extracting data from a typical SOAP request structure
-- Assuming a structure like:
-- <soapenv:Envelope>
--   <soapenv:Body>
--     <web:GetUserInfo>
--       <web:UserId>123</web:UserId>
--       <web:UserName>John Doe &amp; Co.</web:UserName>
--       <web:Email>john.doe@example.com</web:Email>
--     </web:GetUserInfo>
--   </soapenv:Body>
-- </soapenv:Envelope>

local envelope = parsed_xml
local body = find_child(envelope, "soapenv:Body")

if not body then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: SOAP Body not found.")
    ngx.log(ngx.ERR, "SOAP Body not found in XML.")
    return
end

local get_user_info_request = find_child(body, "web:GetUserInfo") -- Adjust namespace prefix 'web' as needed

if not get_user_info_request then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: GetUserInfo request not found in SOAP Body.")
    ngx.log(ngx.ERR, "GetUserInfo request not found in SOAP Body.")
    return
end

local user_id_node = find_child(get_user_info_request, "web:UserId")
local user_name_node = find_child(get_user_info_request, "web:UserName")
local email_node = find_child(get_user_info_request, "web:Email")

local user_id = get_text_content(user_id_node)
local user_name = get_text_content(user_name_node)
local email = get_text_content(email_node)

-- Log extracted data for debugging/processing
ngx.log(ngx.INFO, "Extracted User ID: ", user_id)
ngx.log(ngx.INFO, "Extracted User Name: ", user_name)
ngx.log(ngx.INFO, "Extracted Email: ", email)

-- Perform further processing with the extracted data
-- For example, call an internal service, validate, etc.

