      <web:GetUserInfoResponse xmlns:web="http://www.example.com/webservice">
         <web:Status>Success</web:Status>
         <web:Message>User data processed for ]] .. (user_name or "N/A") .. [[ (ID: ]] .. (user_id or "N/A") .. [[)</web:Message>
      </web:GetUserInfoResponse>
